import osimport argparsefrom obspy import readfrom obspy.clients.fdsn import Clientimport obspy.signalimport numpy as npdef sonify(args):    # Initialize FDSN client    client = Client(args.client)        print(f"Connecting to data center {args.client}")        # Fetch inventory first    inv = client.get_stations(        network=args.network,        station=args.station,        location=args.location,        channel=args.channel,        level="response"    )        # Get waveforms after fetching inventory    stream = client.get_waveforms(        network=args.network,        station=args.station,        location=args.location,        channel=args.channel,        starttime=args.start_time,        endtime=args.end_time    )        print(f"Data fetched successfully")        # Merge streams    stream.merge(fill_value='interpolate')    # Convert to SAC format:
    stream.write("MatSAC/out.sac", format="SAC")


# Copy stream for envelope
    stream1 = stream.copy()        # Get maximum amplitude and index    max_amp = max(abs(stream[0].data))    max_amp_index = abs(stream[0].data).argmax()        # Calculate time range of maximum amplitude    start_time = stream[0].stats.starttime    max_amp_time = start_time + max_amp_index * stream[0].stats.delta    # Calculate duration of maximum amplitude
    # delta is already in seconds in Obspy
    duration = (max_amp_index + 1) * stream[0].stats.delta
    
    # Duration is already in seconds
    duration_seconds = duration        # Print results    print("Maximum amplitude:", max_amp)    print("Time of maximum amplitude:", max_amp_time)    print("Duration of maximum amplitude: {} seconds".format(duration_seconds))        print(f"Preprocessing data.")        # Remove response from inventory    stream.remove_response(inventory=inv, taper=0.01)        # Detrend data    stream.detrend('demean')        # Filter data    stream.filter('bandpass', freqmin=args.fmin, freqmax=args.fmax, corners=2, zerophase=True)# Adjust speed factor    stream.interpolate(sampling_rate=44100/args.speed_factor, method='lanczos', a=20)    stream.taper(0.01)      print(f"Preprocessing of seismic data complete.")# Save raw sound fileraw_output_file = args.outputfile.replace('.wav', '_raw.wav')stream.write(raw_output_file, format='WAV', width=2, rescale=True, framerate=44100)print(f"Raw data saved to {raw_output_file}")#generate envelopeenv = obspy.signal.filter.envelope(stream1[0].data)# Function to generate modulated signaldef generate_modulated_signal(amplitude):    frequency = 400 + (2000 - 400) * amplitude / max_amp    return np.sin(2 * np.pi * frequency * t)# Generate modulated signalt = np.linspace(0, len(env), len(env)*44100//len(stream[0].data))modulated_signal = np.array([generate_modulated_signal(a) for a in env])# Combine raw and modulated signalscombined_signal = stream[0].data * modulated_signal# Save modulated wav filemodulated_output_file = args.outputfile.replace('.wav', '_modulated.wav')np.save(modulated_output_file, combined_signal)print(f"Modulated data saved to {modulated_output_file}")# Main execution blockif __name__ == "__main__":    parser = argparse.ArgumentParser(description="Sonify seismic data.")    parser.add_argument('-C', '--client', type=str, required=True, help='FDSN client for retrieving seismic waveform data. E.G. iris, gfz http://localhost:88080.')    parser.add_argument('-n', '--network', type=str, required=True, help='Network code.')    parser.add_argument('-s', '--station', type=str, required=True, help='Station code.')    parser.add_argument('-l', '--location', type=str, required=True, help='Location code.')    parser.add_argument('-c', '--channel', type=str, required=True, help='Channel code.')    parser.add_argument('-f', '--fmin', type=float, required=True, help='Minimum frequency of the filter.')    parser.add_argument('-F', '--fmax', type=float, required=True, help='Maximum frequency of the filter.')    parser.add_argument('-S', '--speed-factor', type=float, required=True, help='Speed factor for adjusting sample rate.')    parser.add_argument('-o', '--outputfile', type=str, required=True, help='Output file.wav format.')    parser.add_argument('-t', '--timespan', type=str, required=True, help='Start time and end time e.g., "2024-05-25 00:00~2024-05-25 01:00"')        args = parser.parse_args()        # Parse timespan into start_time and end_time    start_time_str, end_time_str = args.timespan.split('~')    # Convert string times to datetime objects    from obspy.core.utcdatetime import UTCDateTime    start_time = UTCDateTime(start_time_str+":00")    end_time = UTCDateTime(end_time_str+":00")        # Update the arguments with the converted datetime objects    args.start_time = start_time    args.end_time = end_time        sonify(args)